<?php
namespace App\Domain\Media\CatalogImages\Data;
use InvalidArgumentException;
final class CatalogImageView{private $urls;private $exists;private $fallback;private $disk;private $path;private $metadata;public function __construct(array $urls,$exists,$fallback,$disk,$path,array $metadata=[]){$this->urls=$urls;$this->exists=(bool)$exists;$this->fallback=(bool)$fallback;$this->disk=$disk;$this->path=$path;$this->metadata=$metadata;}public function url($size){$size=(int)$size;if(!in_array($size,[64,128,256],true))throw new InvalidArgumentException('Tamaño de imagen de catálogo no soportado.');return$this->urls[$size];}public function url64(){return$this->url(64);}public function url128(){return$this->url(128);}public function url256(){return$this->url(256);}public function exists(){return$this->exists;}public function isFallback(){return$this->fallback;}public function disk(){return$this->disk;}public function canonicalPath(){return$this->path;}public function safeMetadata(){return array_merge([],$this->metadata);}}
